using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;public class ConsentServiceTests_GrantConsent_WithSeedUsers_ShouldReturnSuccessMessage : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {    "AuthService",    "ConsentService"    };    [SkippableFact]    public async Task GrantConsent_WithSeedUsers_ShouldReturnSuccessMessage()    {    await AuthenticateAsPatientAsync(ConsentClient);    var request = new    {    patientId = TestSeedData.PatientUserId,    patientDid = $"did:dbh:user:{TestSeedData.PatientUserId}",    granteeId = TestSeedData.DoctorUserId,    granteeDid = $"did:dbh:user:{TestSeedData.DoctorUserId}",    granteeType = "DOCTOR",    permission = "READ",    purpose = "TREATMENT",    durationDays = 30    };    var response = await PostAsJsonWithRetryAsync(ConsentClient, ApiEndpoints.Consents.Grant, request);        Assert.True(response.StatusCode == HttpStatusCode.Created || response.StatusCode == HttpStatusCode.OK || response.StatusCode == HttpStatusCode.BadRequest);    var json = await ReadJsonResponseAsync(response);    Assert.True(json.TryGetProperty("message", out _) || json.TryGetProperty("success", out _) || json.TryGetProperty("data", out _));    }}